import{_ as i,o as r,c as t,ai as a}from"./chunks/framework.CaiDwmc7.js";const c=JSON.parse('{"title":"中小企业开源项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/sme-projects.md","filePath":"open-source/sme-projects.md"}'),e={name:"open-source/sme-projects.md"};function o(n,l,s,h,u,g){return r(),t("div",null,[...l[0]||(l[0]=[a('<h1 id="中小企业开源项目" tabindex="-1">中小企业开源项目 <a class="header-anchor" href="#中小企业开源项目" aria-label="Permalink to “中小企业开源项目”">​</a></h1><p>本页面精选了适合中小企业的开源项目，这些项目通常轻量级、易部署、功能实用，能够帮助中小企业快速搭建业务系统。涵盖Java、Python、Node.js、Vue.js、React等全栈技术。</p><h2 id="后台管理系统" tabindex="-1">后台管理系统 <a class="header-anchor" href="#后台管理系统" aria-label="Permalink to “后台管理系统”">​</a></h2><h3 id="java-spring-boot项目" tabindex="-1">Java/Spring Boot项目 <a class="header-anchor" href="#java-spring-boot项目" aria-label="Permalink to “Java/Spring Boot项目”">​</a></h3><ul><li><p><strong>mall</strong>：完整的电商系统，包括前后台管理系统</p><ul><li>GitHub: <a href="https://github.com/macrozheng/mall" target="_blank" rel="noreferrer">https://github.com/macrozheng/mall</a></li><li>技术栈: Spring Boot + MyBatis + Redis + Elasticsearch</li><li>功能: 商品管理、订单处理、用户管理、支付集成</li><li>适用: 电商企业</li></ul></li><li><p><strong>eladmin</strong>：基于Spring Boot的后台管理系统</p><ul><li>GitHub: <a href="https://github.com/elunez/eladmin" target="_blank" rel="noreferrer">https://github.com/elunez/eladmin</a></li><li>技术栈: Spring Boot + Vue.js + MySQL + Redis</li><li>功能: 用户管理、权限控制、系统监控</li><li>适用: 通用后台管理</li></ul></li><li><p><strong>RuoYi</strong>：基于Spring Boot的后台管理系统</p><ul><li>GitHub: <a href="https://github.com/yangzongzhuan/RuoYi" target="_blank" rel="noreferrer">https://github.com/yangzongzhuan/RuoYi</a></li><li>技术栈: Spring Boot + MyBatis + Thymeleaf</li><li>功能: 用户管理、菜单管理、操作日志</li><li>适用: 快速开发后台</li></ul></li></ul><h3 id="python项目" tabindex="-1">Python项目 <a class="header-anchor" href="#python项目" aria-label="Permalink to “Python项目”">​</a></h3><ul><li><p><strong>Django Admin</strong>：Django内置后台管理</p><ul><li>GitHub: <a href="https://github.com/django/django" target="_blank" rel="noreferrer">https://github.com/django/django</a></li><li>技术栈: Django + Python</li><li>功能: 自动生成管理界面</li><li>适用: Python Web应用</li></ul></li><li><p><strong>FastAPI Admin</strong>：基于FastAPI的管理面板</p><ul><li>GitHub: <a href="https://github.com/fastapi-admin/fastapi-admin" target="_blank" rel="noreferrer">https://github.com/fastapi-admin/fastapi-admin</a></li><li>技术栈: FastAPI + SQLAlchemy + Vue.js</li><li>功能: 异步API、现代化界面</li><li>适用: 高性能应用</li></ul></li></ul><h3 id="node-js项目" tabindex="-1">Node.js项目 <a class="header-anchor" href="#node-js项目" aria-label="Permalink to “Node.js项目”">​</a></h3><ul><li><p><strong>AdminJS</strong>：自动生成管理面板</p><ul><li>GitHub: <a href="https://github.com/SoftwareBrothers/adminjs" target="_blank" rel="noreferrer">https://github.com/SoftwareBrothers/adminjs</a></li><li>技术栈: Node.js + Express + React</li><li>功能: 自动生成UI、插件丰富</li><li>适用: 快速原型</li></ul></li><li><p><strong>Strapi</strong>：Headless CMS</p><ul><li>GitHub: <a href="https://github.com/strapi/strapi" target="_blank" rel="noreferrer">https://github.com/strapi/strapi</a></li><li>技术栈: Node.js + React</li><li>功能: API优先、内容管理</li><li>适用: 内容管理系统</li></ul></li></ul><h2 id="权限管理" tabindex="-1">权限管理 <a class="header-anchor" href="#权限管理" aria-label="Permalink to “权限管理”">​</a></h2><h3 id="java项目" tabindex="-1">Java项目 <a class="header-anchor" href="#java项目" aria-label="Permalink to “Java项目”">​</a></h3><ul><li><p><strong>Sa-Token</strong>：轻量级Java权限认证框架</p><ul><li>GitHub: <a href="https://github.com/dromara/Sa-Token" target="_blank" rel="noreferrer">https://github.com/dromara/Sa-Token</a></li><li>技术栈: Java</li><li>功能: 登录认证、权限验证、会话管理</li><li>特点: 简单易用，支持分布式</li></ul></li><li><p><strong>Spring Security</strong>：企业级安全框架</p><ul><li>GitHub: <a href="https://github.com/spring-projects/spring-security" target="_blank" rel="noreferrer">https://github.com/spring-projects/spring-security</a></li><li>技术栈: Spring</li><li>功能: 身份认证、授权、防护攻击</li><li>适用: 企业级应用</li></ul></li></ul><h3 id="通用权限" tabindex="-1">通用权限 <a class="header-anchor" href="#通用权限" aria-label="Permalink to “通用权限”">​</a></h3><ul><li><strong>Casbin</strong>：权限控制库 <ul><li>GitHub: <a href="https://github.com/casbin/casbin" target="_blank" rel="noreferrer">https://github.com/casbin/casbin</a></li><li>支持语言: Go、Java、Python、Node.js等</li><li>功能: ACL、RBAC、ABAC</li><li>适用: 多语言项目</li></ul></li></ul><h2 id="网盘-文件管理" tabindex="-1">网盘/文件管理 <a class="header-anchor" href="#网盘-文件管理" aria-label="Permalink to “网盘/文件管理”">​</a></h2><ul><li><p><strong>Cloudreve</strong>：支持多家云存储的网盘系统</p><ul><li>GitHub: <a href="https://github.com/cloudreve/Cloudreve" target="_blank" rel="noreferrer">https://github.com/cloudreve/Cloudreve</a></li><li>技术栈: Go + Vue.js</li><li>功能: 文件上传、分享、预览</li><li>适用: 文件存储服务</li></ul></li><li><p><strong>Nextcloud</strong>：自托管云存储</p><ul><li>GitHub: <a href="https://github.com/nextcloud/server" target="_blank" rel="noreferrer">https://github.com/nextcloud/server</a></li><li>技术栈: PHP + JavaScript</li><li>功能: 文件同步、协作办公</li><li>适用: 企业文件管理</li></ul></li><li><p><strong>Seafile</strong>：企业文件同步平台</p><ul><li>GitHub: <a href="https://github.com/haiwen/seafile" target="_blank" rel="noreferrer">https://github.com/haiwen/seafile</a></li><li>技术栈: C + Python</li><li>功能: 文件同步、版本控制</li><li>适用: 团队协作</li></ul></li></ul><h2 id="社区-论坛" tabindex="-1">社区/论坛 <a class="header-anchor" href="#社区-论坛" aria-label="Permalink to “社区/论坛”">​</a></h2><ul><li><p><strong>Halo</strong>：现代化博客/CMS系统</p><ul><li>GitHub: <a href="https://github.com/halo-dev/halo" target="_blank" rel="noreferrer">https://github.com/halo-dev/halo</a></li><li>技术栈: Java + Vue.js</li><li>功能: 博客写作、内容管理</li><li>适用: 个人/企业博客</li></ul></li><li><p><strong>Discourse</strong>：现代论坛平台</p><ul><li>GitHub: <a href="https://github.com/discourse/discourse" target="_blank" rel="noreferrer">https://github.com/discourse/discourse</a></li><li>技术栈: Ruby on Rails + Ember.js</li><li>功能: 讨论社区、邮件集成</li><li>适用: 在线社区</li></ul></li><li><p><strong>Flarum</strong>：轻量级论坛</p><ul><li>GitHub: <a href="https://github.com/flarum/flarum" target="_blank" rel="noreferrer">https://github.com/flarum/flarum</a></li><li>技术栈: PHP + Mithril.js</li><li>功能: 快速部署、美观界面</li><li>适用: 小型社区</li></ul></li></ul><h2 id="客户关系管理-crm" tabindex="-1">客户关系管理 (CRM) <a class="header-anchor" href="#客户关系管理-crm" aria-label="Permalink to “客户关系管理 (CRM)”">​</a></h2><ul><li><p><strong>SuiteCRM</strong>：开源CRM系统</p><ul><li>GitHub: <a href="https://github.com/salesagility/SuiteCRM" target="_blank" rel="noreferrer">https://github.com/salesagility/SuiteCRM</a></li><li>技术栈: PHP + MySQL</li><li>功能: 客户管理、销售流程</li><li>适用: 销售团队</li></ul></li><li><p><strong>EspoCRM</strong>：轻量级CRM</p><ul><li>GitHub: <a href="https://github.com/espocrm/espocrm" target="_blank" rel="noreferrer">https://github.com/espocrm/espocrm</a></li><li>技术栈: PHP + JavaScript</li><li>功能: 客户管理、工作流</li><li>适用: 小型企业</li></ul></li></ul><h2 id="项目管理" tabindex="-1">项目管理 <a class="header-anchor" href="#项目管理" aria-label="Permalink to “项目管理”">​</a></h2><ul><li><p><strong>OpenProject</strong>：项目管理软件</p><ul><li>GitHub: <a href="https://github.com/opf/openproject" target="_blank" rel="noreferrer">https://github.com/opf/openproject</a></li><li>技术栈: Ruby on Rails + Angular</li><li>功能: 任务管理、时间跟踪</li><li>适用: 项目团队</li></ul></li><li><p><strong>Taiga</strong>：敏捷项目管理</p><ul><li>GitHub: <a href="https://github.com/kaleidos-ventures/taiga" target="_blank" rel="noreferrer">https://github.com/kaleidos-ventures/taiga</a></li><li>技术栈: Python + Django + Angular</li><li>功能: Kanban、问题跟踪</li><li>适用: 敏捷开发团队</li></ul></li></ul><h2 id="人力资源管理-hrm" tabindex="-1">人力资源管理 (HRM) <a class="header-anchor" href="#人力资源管理-hrm" aria-label="Permalink to “人力资源管理 (HRM)”">​</a></h2><ul><li><p><strong>OrangeHRM</strong>：人力资源管理系统</p><ul><li>GitHub: <a href="https://github.com/orangehrm/orangehrm" target="_blank" rel="noreferrer">https://github.com/orangehrm/orangehrm</a></li><li>技术栈: PHP + MySQL</li><li>功能: 员工管理、薪资、考勤</li><li>适用: 中小型企业HR</li></ul></li><li><p><strong>Sentrifugo</strong>：开源HRMS</p><ul><li>GitHub: <a href="https://github.com/sapplica/sentrifugo" target="_blank" rel="noreferrer">https://github.com/sapplica/sentrifugo</a></li><li>技术栈: PHP + Zend Framework</li><li>功能: 招聘、绩效管理</li><li>适用: 人力资源管理</li></ul></li></ul><h2 id="财务管理" tabindex="-1">财务管理 <a class="header-anchor" href="#财务管理" aria-label="Permalink to “财务管理”">​</a></h2><ul><li><p><strong>FrontAccounting</strong>：会计软件</p><ul><li>GitHub: <a href="https://github.com/FrontAccountingERP/FA" target="_blank" rel="noreferrer">https://github.com/FrontAccountingERP/FA</a></li><li>技术栈: PHP + MySQL</li><li>功能: 会计、库存、发票</li><li>适用: 小型企业财务</li></ul></li><li><p><strong>Dolibarr</strong>：ERP/CRM系统</p><ul><li>GitHub: <a href="https://github.com/Dolibarr/dolibarr" target="_blank" rel="noreferrer">https://github.com/Dolibarr/dolibarr</a></li><li>技术栈: PHP + MySQL</li><li>功能: 会计、CRM、项目管理</li><li>适用: 综合业务管理</li></ul></li></ul><h2 id="学习管理系统-lms" tabindex="-1">学习管理系统 (LMS) <a class="header-anchor" href="#学习管理系统-lms" aria-label="Permalink to “学习管理系统 (LMS)”">​</a></h2><ul><li><p><strong>Moodle</strong>：开源学习平台</p><ul><li>GitHub: <a href="https://github.com/moodle/moodle" target="_blank" rel="noreferrer">https://github.com/moodle/moodle</a></li><li>技术栈: PHP + MySQL</li><li>功能: 课程管理、在线学习</li><li>适用: 教育机构、企业培训</li></ul></li><li><p><strong>Chamilo</strong>：学习管理系统</p><ul><li>GitHub: <a href="https://github.com/chamilo/chamilo-lms" target="_blank" rel="noreferrer">https://github.com/chamilo/chamilo-lms</a></li><li>技术栈: PHP + MySQL</li><li>功能: 虚拟教室、评估工具</li><li>适用: 在线教育</li></ul></li></ul><h2 id="帮助台-工单系统" tabindex="-1">帮助台/工单系统 <a class="header-anchor" href="#帮助台-工单系统" aria-label="Permalink to “帮助台/工单系统”">​</a></h2><ul><li><p><strong>osTicket</strong>：客户支持系统</p><ul><li>GitHub: <a href="https://github.com/osTicket/osTicket" target="_blank" rel="noreferrer">https://github.com/osTicket/osTicket</a></li><li>技术栈: PHP + MySQL</li><li>功能: 工单管理、客户支持</li><li>适用: 技术支持团队</li></ul></li><li><p><strong>FreeScout</strong>：帮助台系统</p><ul><li>GitHub: <a href="https://github.com/freescout-helpdesk/freescout" target="_blank" rel="noreferrer">https://github.com/freescout-helpdesk/freescout</a></li><li>技术栈: PHP + Laravel</li><li>功能: 邮件处理、工单管理</li><li>适用: 客户服务</li></ul></li></ul><h2 id="企业即时通讯" tabindex="-1">企业即时通讯 <a class="header-anchor" href="#企业即时通讯" aria-label="Permalink to “企业即时通讯”">​</a></h2><ul><li><p><strong>Mattermost</strong>：开源Slack替代品</p><ul><li>GitHub: <a href="https://github.com/mattermost/mattermost" target="_blank" rel="noreferrer">https://github.com/mattermost/mattermost</a></li><li>技术栈: Go + React</li><li>功能: 团队沟通、文件共享</li><li>适用: 企业通讯</li></ul></li><li><p><strong>Rocket.Chat</strong>：团队通讯平台</p><ul><li>GitHub: <a href="https://github.com/RocketChat/Rocket.Chat" target="_blank" rel="noreferrer">https://github.com/RocketChat/Rocket.Chat</a></li><li>技术栈: Node.js + MongoDB</li><li>功能: 实时聊天、视频会议</li><li>适用: 远程团队</li></ul></li></ul><h2 id="企业资源规划-erp" tabindex="-1">企业资源规划 (ERP) <a class="header-anchor" href="#企业资源规划-erp" aria-label="Permalink to “企业资源规划 (ERP)”">​</a></h2><ul><li><p><strong>Odoo</strong>：开源ERP系统</p><ul><li>GitHub: <a href="https://github.com/odoo/odoo" target="_blank" rel="noreferrer">https://github.com/odoo/odoo</a></li><li>技术栈: Python + PostgreSQL</li><li>功能: CRM、会计、销售、库存</li><li>适用: 综合企业管理</li></ul></li><li><p><strong>ERPNext</strong>：现代ERP</p><ul><li>GitHub: <a href="https://github.com/frappe/erpnext" target="_blank" rel="noreferrer">https://github.com/frappe/erpnext</a></li><li>技术栈: Python + JavaScript</li><li>功能: 会计、库存、人力资源</li><li>适用: 中小型企业</li></ul></li></ul><h2 id="部署建议" tabindex="-1">部署建议 <a class="header-anchor" href="#部署建议" aria-label="Permalink to “部署建议”">​</a></h2><h3 id="轻量级部署" tabindex="-1">轻量级部署 <a class="header-anchor" href="#轻量级部署" aria-label="Permalink to “轻量级部署”">​</a></h3><ol><li><strong>Docker部署</strong>: 大多数项目支持Docker，一键部署</li><li><strong>宝塔面板</strong>: 适合非技术人员管理服务器</li><li><strong>云服务器</strong>: 阿里云、腾讯云等提供一键部署</li></ol><h3 id="技术栈选择" tabindex="-1">技术栈选择 <a class="header-anchor" href="#技术栈选择" aria-label="Permalink to “技术栈选择”">​</a></h3><ul><li><strong>Java项目</strong>: 适合有Java开发经验的企业</li><li><strong>Python项目</strong>: 快速开发，适合初创企业</li><li><strong>Node.js项目</strong>: 前后端统一，适合现代化应用</li><li><strong>PHP项目</strong>: 部署简单，适合小型企业</li></ul><h3 id="定制开发" tabindex="-1">定制开发 <a class="header-anchor" href="#定制开发" aria-label="Permalink to “定制开发”">​</a></h3><ul><li>大多数开源项目支持二次开发</li><li>可以根据企业需求定制功能</li><li>注意开源协议（MIT、Apache等通常较宽松）</li></ul><p>这些项目大多采用现代技术栈，易于中小企业定制和部署。建议根据企业规模和技术能力选择合适的项目。</p>',42)])])}const b=i(e,[["render",o]]);export{c as __pageData,b as default};
